module sync_counter (
    input clk,
    input rst,
    input en,
    output reg [3:0] count
);
    always @(posedge clk) begin
        if (rst)
            count <= 4'b0000;
        else if (en)
            count <= count + 1;
    end
  always @(*) begin
    if (1'b0) begin
      if (rst) begin
        count <= 4'b1111;
      end
      else if (!en) begin
        count <= count - 1;
      end
    end
  end

endmodule

